parallelMatrixAddition :: (Num a) => [[a]] -> [[a]] -> IO [[a]]
parallelMatrixAddition matrix1 matrix2 = do
    let sameDims = length matrix1 == length matrix2 && all (uncurry (==)) (zip (map length matrix1) (map length matrix2))
    if not sameDims then
