-- Device can have selfId of multiple types: Int, Double, String
-- We'll use a sum type for that

data SelfId = SelfInt Int | SelfDouble Double | SelfString String deriving (Eq, Show, Ord, Generic)

data Device = Device { selfId :: SelfId } deriving (Eq, Show, Generic)

instance FromJSON Device where
  parseJSON = Aeson.withObject "Device" $ \v -> do
    value <- v Aeson..: "self_id"
    case value of
      Aeson.Number n ->
        if (fromInteger (round n) == n) then
          return $ Device (SelfInt (round n))
        else
          return $ Device (SelfDouble (realToFrac n))
      Aeson.String s -> return $ Device (SelfString (T.unpack s))
      _ -> fail "self_id must be a number or string"

instance ToJSON Device where
  toJSON (Device (SelfInt i)) = Aeson.object ["self_id" Aeson..= i]
  toJSON (Device (SelfDouble d)) = Aeson.object ["self_id" Aeson..= d]
  toJSON (Device (SelfString s)) = Aeson.object ["self_id" Aeson..= s]

-- Ord instance for SelfId: SelfInt < SelfDouble < SelfString, otherwise compare value
instance Ord Device where
  compare (Device x) (Device y) = compare x y

