data Article = Article { title :: String, content :: String } deriving (Eq, Show)

extractTitlesWithKeyword :: [Article] -> String -> [String]
extractTitlesWithKeyword articles keyword =
  [title article | article <- articles, map toLower keyword `isInfixOf` map toLower (content article)]

