import qualified Data.Map.Strict as Map
import Data.Char (toUpper)
import Data.List (sort)

organizeSpecies :: [String] -> Map.Map Char [String]
organizeSpecies speciesList =
    let sortedSpecies = sort speciesList
        insertSpecies m species =
            let firstLetter = toUpper (head species)
            in Map.insertWith (\new old -> old ++ new) firstLetter [species] m
    in Map.map reverse $ foldl insertSpecies Map.empty sortedSpecies

