simulateTrapezeSwing :: Double -> Double -> Int -> [(Int, Double)]
simulateTrapezeSwing length angle time =
  let g = 9.81 -- Acceleration due to gravity (m/s^2)
      angleRad = angle * pi / 180
      period = 2 * pi * sqrt (length / g)
      amplitude = length * sin angleRad
      times = [0..time]
      displacements = [amplitude * cos (2 * pi * fromIntegral t / period) | t <- times]
  in zip times displacements

